import { describe, expect, it, vi } from "vitest";
import { buildHelp, buildUsage, parseArgs, positionalArgs, printHelpIfRequested, } from "./parseArgs.js";
describe("positionalArgs", () => {
    it("returns positional args matching schema", () => {
        const result = positionalArgs([{ name: "functionKey" }, { name: "datasetId", format: "uuid" }], [
            "node",
            "startDataset.js",
            "my-func",
            "a1b2c3d4-e5f6-7890-abcd-ef1234567890",
        ]);
        expect(result).toEqual(["my-func", "a1b2c3d4-e5f6-7890-abcd-ef1234567890"]);
    });
    it("returns empty array for schema with no required args", () => {
        const result = positionalArgs([{ name: "message", required: false }], ["node", "script.js"]);
        expect(result).toEqual([]);
    });
    it("exits with error when flags are present", () => {
        const mockExit = vi
            .spyOn(process, "exit")
            .mockImplementation(() => undefined);
        const mockError = vi.spyOn(console, "error").mockImplementation(() => { });
        positionalArgs([{ name: "planId", format: "uuid" }], ["node", "openTracePlan.js", "--planId", "abc-123"]);
        expect(mockExit).toHaveBeenCalledWith(1);
        expect(mockError).toHaveBeenCalledWith(expect.stringContaining("Unknown flag: --planId"));
        mockExit.mockRestore();
        mockError.mockRestore();
    });
    it("exits when too few args provided", () => {
        const mockExit = vi
            .spyOn(process, "exit")
            .mockImplementation(() => undefined);
        const mockError = vi.spyOn(console, "error").mockImplementation(() => { });
        positionalArgs([{ name: "functionKey" }, { name: "datasetId", format: "uuid" }], ["node", "startDataset.js", "my-func"]);
        expect(mockExit).toHaveBeenCalledWith(1);
        expect(mockError).toHaveBeenCalledWith(expect.stringContaining("Expected at least 2"));
        mockExit.mockRestore();
        mockError.mockRestore();
    });
    it("exits when too many args provided", () => {
        const mockExit = vi
            .spyOn(process, "exit")
            .mockImplementation(() => undefined);
        const mockError = vi.spyOn(console, "error").mockImplementation(() => { });
        positionalArgs([{ name: "planId", format: "uuid" }], ["node", "openTracePlan.js", "id-1", "id-2"]);
        expect(mockExit).toHaveBeenCalledWith(1);
        expect(mockError).toHaveBeenCalledWith(expect.stringContaining("Expected at most 1"));
        mockExit.mockRestore();
        mockError.mockRestore();
    });
    it("exits when uuid format is invalid", () => {
        const mockExit = vi
            .spyOn(process, "exit")
            .mockImplementation(() => undefined);
        const mockError = vi.spyOn(console, "error").mockImplementation(() => { });
        positionalArgs([{ name: "planId", format: "uuid" }], ["node", "openTracePlan.js", "not-a-uuid"]);
        expect(mockExit).toHaveBeenCalledWith(1);
        expect(mockError).toHaveBeenCalledWith(expect.stringContaining('"not-a-uuid" is not a valid UUID'));
        mockExit.mockRestore();
        mockError.mockRestore();
    });
    it("accepts variadic args", () => {
        const result = positionalArgs([{ name: "testRunId", variadic: true }], [
            "node",
            "openExperiments.js",
            "a1b2c3d4-e5f6-7890-abcd-ef1234567890",
            "b2c3d4e5-f6a7-8901-bcde-f12345678901",
        ]);
        expect(result).toEqual([
            "a1b2c3d4-e5f6-7890-abcd-ef1234567890",
            "b2c3d4e5-f6a7-8901-bcde-f12345678901",
        ]);
    });
    it("allows optional args to be omitted", () => {
        const result = positionalArgs([
            { name: "sessionId", format: "uuid" },
            { name: "message", required: false },
        ], ["node", "closeStudio.js", "a1b2c3d4-e5f6-7890-abcd-ef1234567890"]);
        expect(result).toEqual(["a1b2c3d4-e5f6-7890-abcd-ef1234567890"]);
    });
    it("prints the usageNote on arg failure", () => {
        const mockExit = vi
            .spyOn(process, "exit")
            .mockImplementation(() => undefined);
        const mockError = vi.spyOn(console, "error").mockImplementation(() => { });
        positionalArgs([{ name: "functionKey" }, { name: "datasetId", format: "uuid" }], ["node", "startDataset.js"], { usageNote: "BLOCKING: stays alive until Done." });
        expect(mockExit).toHaveBeenCalledWith(1);
        expect(mockError).toHaveBeenCalledWith("BLOCKING: stays alive until Done.");
        mockExit.mockRestore();
        mockError.mockRestore();
    });
});
describe("parseArgs", () => {
    it("parses positional args with flags", () => {
        const result = parseArgs({
            positional: [{ name: "traceFunctionKey" }],
            flags: [
                { name: "timeout-ms", format: "number", default: 600000 },
                { name: "poll-interval-ms", format: "number", default: 10000 },
            ],
            argv: ["node", "waitForTrace.js", "my-function", "--timeout-ms", "30000"],
        });
        expect(result.positional).toEqual(["my-function"]);
        expect(result.flags["timeout-ms"]).toBe(30000);
        expect(result.flags["poll-interval-ms"]).toBe(10000);
    });
    it("uses flag defaults when not provided", () => {
        const result = parseArgs({
            positional: [{ name: "traceFunctionKey" }],
            flags: [{ name: "timeout-ms", format: "number", default: 600000 }],
            argv: ["node", "waitForTrace.js", "my-function"],
        });
        expect(result.positional).toEqual(["my-function"]);
        expect(result.flags["timeout-ms"]).toBe(600000);
    });
    it("handles flags interspersed with positional args", () => {
        const result = parseArgs({
            positional: [
                { name: "targetPath", required: false },
                { name: "agentSessionId", required: false },
            ],
            flags: [{ name: "existing", format: "uuid" }],
            argv: [
                "node",
                "openStudio.js",
                "--existing",
                "a1b2c3d4-e5f6-7890-abcd-ef1234567890",
                "agent-123",
            ],
        });
        expect(result.flags.existing).toBe("a1b2c3d4-e5f6-7890-abcd-ef1234567890");
        expect(result.positional).toEqual(["agent-123"]);
    });
    it("exits on unknown flags", () => {
        const mockExit = vi
            .spyOn(process, "exit")
            .mockImplementation(() => undefined);
        const mockError = vi.spyOn(console, "error").mockImplementation(() => { });
        parseArgs({
            positional: [{ name: "key" }],
            flags: [],
            argv: ["node", "cmd.js", "val", "--bogus", "x"],
        });
        expect(mockExit).toHaveBeenCalledWith(1);
        expect(mockError).toHaveBeenCalledWith(expect.stringContaining("Unknown flag: --bogus"));
        mockExit.mockRestore();
        mockError.mockRestore();
    });
    it("exits when flag value is missing", () => {
        const mockExit = vi
            .spyOn(process, "exit")
            .mockImplementation(() => undefined);
        const mockError = vi.spyOn(console, "error").mockImplementation(() => { });
        parseArgs({
            positional: [{ name: "key" }],
            flags: [{ name: "timeout-ms", format: "number" }],
            argv: ["node", "cmd.js", "val", "--timeout-ms"],
        });
        expect(mockExit).toHaveBeenCalledWith(1);
        expect(mockError).toHaveBeenCalledWith(expect.stringContaining("--timeout-ms requires a value"));
        mockExit.mockRestore();
        mockError.mockRestore();
    });
    it("exits when flag value has wrong format", () => {
        const mockExit = vi
            .spyOn(process, "exit")
            .mockImplementation(() => undefined);
        const mockError = vi.spyOn(console, "error").mockImplementation(() => { });
        parseArgs({
            positional: [{ name: "key" }],
            flags: [{ name: "timeout-ms", format: "number" }],
            argv: ["node", "cmd.js", "val", "--timeout-ms", "abc"],
        });
        expect(mockExit).toHaveBeenCalledWith(1);
        expect(mockError).toHaveBeenCalledWith(expect.stringContaining('"abc" is not a valid positive number'));
        mockExit.mockRestore();
        mockError.mockRestore();
    });
    it("works with no flags specified", () => {
        const result = parseArgs({
            positional: [{ name: "planId", format: "uuid" }],
            argv: [
                "node",
                "openTracePlan.js",
                "a1b2c3d4-e5f6-7890-abcd-ef1234567890",
            ],
        });
        expect(result.positional).toEqual(["a1b2c3d4-e5f6-7890-abcd-ef1234567890"]);
        expect(result.flags).toEqual({});
    });
    it("sets a boolean flag to true when present, consuming no value", () => {
        const result = parseArgs({
            positional: [{ name: "testRunId", variadic: true }],
            flags: [{ name: "show-tokens", boolean: true }],
            argv: [
                "node",
                "openExperiments.js",
                "aaaaaaaa-aaaa-aaaa-aaaa-aaaaaaaaaaaa",
                "--show-tokens",
            ],
        });
        expect(result.flags["show-tokens"]).toBe(true);
        expect(result.positional).toEqual(["aaaaaaaa-aaaa-aaaa-aaaa-aaaaaaaaaaaa"]);
    });
    it("leaves a boolean flag unset when absent", () => {
        const result = parseArgs({
            positional: [{ name: "testRunId", variadic: true }],
            flags: [{ name: "show-tokens", boolean: true }],
            argv: [
                "node",
                "openExperiments.js",
                "aaaaaaaa-aaaa-aaaa-aaaa-aaaaaaaaaaaa",
            ],
        });
        expect(result.flags["show-tokens"]).toBeUndefined();
    });
    it("omits the usageNote line when not provided", () => {
        const mockExit = vi
            .spyOn(process, "exit")
            .mockImplementation(() => undefined);
        const mockError = vi.spyOn(console, "error").mockImplementation(() => { });
        parseArgs({
            positional: [{ name: "key" }],
            argv: ["node", "cmd.js"],
        });
        expect(mockExit).toHaveBeenCalledWith(1);
        // Exactly two lines: usage + error message, no note in between.
        expect(mockError).toHaveBeenCalledTimes(2);
        expect(mockError).toHaveBeenNthCalledWith(1, "Usage: cmd <key>");
        expect(mockError).toHaveBeenNthCalledWith(2, "Expected at least 1 argument, got 0.");
        mockExit.mockRestore();
        mockError.mockRestore();
    });
});
describe("buildUsage", () => {
    it("formats required args", () => {
        expect(buildUsage("startDataset", [
            { name: "functionKey" },
            { name: "datasetId", format: "uuid" },
        ])).toBe("Usage: startDataset <functionKey> <datasetId:uuid>");
    });
    it("formats optional args", () => {
        expect(buildUsage("closeStudio", [
            { name: "sessionId", format: "uuid" },
            { name: "message", required: false },
        ])).toBe("Usage: closeStudio <sessionId:uuid> [message]");
    });
    it("formats variadic args", () => {
        expect(buildUsage("openExperiments", [{ name: "testRunId", variadic: true }])).toBe("Usage: openExperiments <testRunId> [<testRunId>...]");
    });
    it("formats mixed positional and flag args", () => {
        expect(buildUsage("waitForTrace", [{ name: "traceFunctionKey" }], [
            { name: "timeout-ms", format: "number", default: 600000 },
            { name: "poll-interval-ms", format: "number", default: 10000 },
        ])).toBe("Usage: waitForTrace <traceFunctionKey> [--timeout-ms N (default: 600000)] [--poll-interval-ms N (default: 10000)]");
    });
});
describe("help", () => {
    it("prints help and exits 0 on --help", () => {
        // Throw from the mock so execution stops at the exit call, like a real exit.
        const mockExit = vi.spyOn(process, "exit").mockImplementation(() => {
            throw new Error("process.exit");
        });
        const mockLog = vi.spyOn(console, "log").mockImplementation(() => { });
        expect(() => parseArgs({
            positional: [{ name: "planId", format: "uuid" }],
            argv: ["node", "openTracePlan.js", "--help"],
            description: "Open a trace plan in Studio.",
        })).toThrow("process.exit");
        expect(mockExit).toHaveBeenCalledWith(0);
        expect(mockLog).toHaveBeenCalledWith(expect.stringContaining("Usage: openTracePlan <planId:uuid>"));
        expect(mockLog).toHaveBeenCalledWith(expect.stringContaining("Open a trace plan in Studio."));
        mockExit.mockRestore();
        mockLog.mockRestore();
    });
    it("prints help and exits 0 on -h, even with other args present", () => {
        const mockExit = vi.spyOn(process, "exit").mockImplementation(() => {
            throw new Error("process.exit");
        });
        const mockLog = vi.spyOn(console, "log").mockImplementation(() => { });
        expect(() => positionalArgs([{ name: "functionKey" }], ["node", "startDataset.js", "my-func", "-h"], {
            description: "Open a dataset in Studio.",
        })).toThrow("process.exit");
        expect(mockExit).toHaveBeenCalledWith(0);
        expect(mockLog).toHaveBeenCalledWith(expect.stringContaining("Open a dataset in Studio."));
        mockExit.mockRestore();
        mockLog.mockRestore();
    });
    it("buildHelp includes argument and flag descriptions", () => {
        const help = buildHelp("waitForTrace", [
            {
                name: "traceFunctionKey",
                description: "Trace function key to watch.",
            },
        ], [
            {
                name: "timeout-ms",
                format: "number",
                default: 600000,
                description: "How long to poll.",
            },
        ], "Block until the first trace arrives.");
        expect(help).toContain("Usage: waitForTrace <traceFunctionKey> [--timeout-ms N (default: 600000)]");
        expect(help).toContain("Block until the first trace arrives.");
        expect(help).toContain("Arguments:");
        expect(help).toContain("traceFunctionKey");
        expect(help).toContain("Trace function key to watch.");
        expect(help).toContain("Flags:");
        expect(help).toContain("--timeout-ms");
        expect(help).toContain("How long to poll. (default: 600000)");
    });
    it("buildHelp omits empty sections", () => {
        const help = buildHelp("logout", [], undefined, "Log out of Bitfab.");
        expect(help).toBe("Usage: logout\n\nLog out of Bitfab.");
    });
    it("printHelpIfRequested no-ops without -h/--help", () => {
        const mockExit = vi
            .spyOn(process, "exit")
            .mockImplementation(() => undefined);
        const mockLog = vi.spyOn(console, "log").mockImplementation(() => { });
        printHelpIfRequested({
            description: "Log out of Bitfab.",
            argv: ["node", "logout.js"],
        });
        expect(mockExit).not.toHaveBeenCalled();
        expect(mockLog).not.toHaveBeenCalled();
        mockExit.mockRestore();
        mockLog.mockRestore();
    });
    it("printHelpIfRequested prints help and exits 0 on -h", () => {
        const mockExit = vi.spyOn(process, "exit").mockImplementation(() => {
            throw new Error("process.exit");
        });
        const mockLog = vi.spyOn(console, "log").mockImplementation(() => { });
        expect(() => printHelpIfRequested({
            description: "Log out of Bitfab.",
            argv: ["node", "logout.js", "-h"],
        })).toThrow("process.exit");
        expect(mockExit).toHaveBeenCalledWith(0);
        expect(mockLog).toHaveBeenCalledWith(expect.stringContaining("Log out of Bitfab."));
        mockExit.mockRestore();
        mockLog.mockRestore();
    });
});
